import React, { useState, useEffect } from 'react';
import axios from 'axios';
import AuthService from '../services/AuthService';

function MyApplications() {
  const [applications, setApplications] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [filter, setFilter] = useState('ALL');

  useEffect(() => {
    fetchApplications();
  }, []);

  const fetchApplications = async () => {
    try {
      const response = await axios.get(
        'http://localhost:8080/api/applications/my-applications',
        {
          headers: {
            'Authorization': 'Bearer ' + AuthService.getToken()
          }
        }
      );
      setApplications(response.data);
      setLoading(false);
    } catch (err) {
      setError('Không thể tải danh sách ứng tuyển');
      setLoading(false);
    }
  };

  const getStatusColor = (status) => {
    switch (status) {
      case 'SUBMITTED':
        return 'status-submitted';
      case 'REVIEWING':
        return 'status-reviewing';
      case 'INTERVIEW':
        return 'status-interview';
      case 'ACCEPTED':
        return 'status-accepted';
      case 'REJECTED':
        return 'status-rejected';
      default:
        return '';
    }
  };

  const getStatusLabel = (status) => {
    const labels = {
      'SUBMITTED': '📝 Đã nộp',
      'REVIEWING': '👁️ Đang xem xét',
      'INTERVIEW': '🎤 Mời phỏng vấn',
      'ACCEPTED': '✅ Chấp nhận',
      'REJECTED': '❌ Từ chối'
    };
    return labels[status] || status;
  };

  const filteredApplications = filter === 'ALL' 
    ? applications 
    : applications.filter(app => app.status === filter);

  if (loading) {
    return <div className="container"><p>Đang tải...</p></div>;
  }

  return (
    <div className="container">
      <h2>Đơn Ứng Tuyển Của Tôi</h2>

      {error && <div className="alert alert-danger">{error}</div>}

      <div className="applications-filter">
        <select 
          value={filter} 
          onChange={(e) => setFilter(e.target.value)}
          className="form-control"
        >
          <option value="ALL">Tất cả trạng thái</option>
          <option value="SUBMITTED">Đã nộp</option>
          <option value="REVIEWING">Đang xem xét</option>
          <option value="INTERVIEW">Mời phỏng vấn</option>
          <option value="ACCEPTED">Chấp nhận</option>
          <option value="REJECTED">Từ chối</option>
        </select>
      </div>

      {filteredApplications.length === 0 ? (
        <div className="empty-state">
          <p>Bạn chưa ứng tuyển công việc nào</p>
        </div>
      ) : (
        <div className="applications-list">
          {filteredApplications.map((app) => (
            <div key={app.id} className={`application-card ${getStatusColor(app.status)}`}>
              <div className="application-header">
                <h3>{app.jobPost.title}</h3>
                <span className={`status-badge ${getStatusColor(app.status)}`}>
                  {getStatusLabel(app.status)}
                </span>
              </div>

              <div className="application-details">
                <p>
                  <strong>Công ty:</strong> {app.jobPost.employer?.username || 'N/A'}
                </p>
                <p>
                  <strong>Địa điểm:</strong> {app.jobPost.location || 'N/A'}
                </p>
                <p>
                  <strong>Mức lương:</strong> ${app.jobPost.salary?.toLocaleString() || 'Thỏa thuận'}
                </p>
                <p>
                  <strong>Ngày nộp:</strong> {new Date(app.appliedAt).toLocaleDateString('vi-VN')}
                </p>
              </div>

              <div className="application-description">
                <p>{app.jobPost.description?.substring(0, 100)}...</p>
              </div>

              {app.status === 'INTERVIEW' && (
                <div className="alert alert-success">
                  🎉 Chúc mừng! Bạn được mời phỏng vấn. Vui lòng kiểm tra email của bạn để biết chi tiết.
                </div>
              )}

              {app.status === 'ACCEPTED' && (
                <div className="alert alert-success">
                  🎊 Xin chúc mừng! Bạn đã được chấp nhận. Hãy liên hệ công ty để làm các thủ tục tiếp theo.
                </div>
              )}

              {app.status === 'REJECTED' && (
                <div className="alert alert-danger">
                  😔 Rất tiếc, đơn ứng tuyển của bạn không được chấp nhận. Hãy thử ứng tuyển các công việc khác.
                </div>
              )}
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

export default MyApplications;
